class Dog {
  String name; // The Object's internal attribute

  // The parameter 'name' comes from outside
  Dog(String name) {
    // this.name refers to the Object
    // name refers to the parameter inbox
    this.name = name;
  }
}

class Main {
  public static void main(String[] args) {
    Dog d = new Dog("Rex");
    System.out.println(d.name);
  }
}
